const crypto = require('crypto');
let data;
try { data = JSON.parse(msg.payload); } catch(e) {
  node.warn('Bad JSON from: ' + msg.topic);
  return null;
}
const parts = msg.topic.split('/');
const received = data.hash;
delete data.hash;
const canonical = JSON.stringify(data, Object.keys(data).sort());
const computed = crypto.createHash('sha256').update(canonical).digest('hex');
if (computed !== received) {
  msg.payload = { alert:'HASH_MISMATCH', topic: msg.topic, computed, received, ts: Date.now() };
  node.send([null, msg]);
  return;
}
msg.validData = data;
msg.buildingId = parts[1];
msg.floorId = parts[2];
node.send([msg, null]);

const bld = msg.buildingId;
const flr = msg.floorId;
const floors = (flr === '+') ?
  ['f01','f02','f03','f04','f05','f06','f07','f08','f09','f10'] : [flr];
const out = [];
for (const f of floors) {
  for (let r = 1; r <= 20; r++) {
    const rid = 'r' + String(r).padStart(3,'0');
    out.push({
      topic: `campus/${bld}/${f}/cmd/${rid}`,
      payload: JSON.stringify({ method:'applyConfig', params: msg.validData }),
      qos: 1
    });
  }
}
return [out];

msg.url = global.get('TB_URL') + '/api/plugins/telemetry/DEVICE/' + (global.get('ALERT_DEVICE_ID') || 'unknown') + '/timeseries';
msg.headers = { 'X-Authorization': 'Bearer ' + global.get('TB_TOKEN'), 'Content-Type':'application/json' };
msg.method = 'POST';
return msg;

const parts = msg.topic.split('/');
msg.buildingId = parts[1];
msg.floorId    = parts[2];
msg.roomId     = parts[3];
msg.deviceKey  = `${parts[1]}-${parts[2]}-${parts[3]}`;
let reported;
try { reported = JSON.parse(msg.payload); } catch(e) { return null; }
msg.reported = reported;
const desired_hvac   = flow.get('desired_hvac_'   + msg.deviceKey);
const desired_dimmer = flow.get('desired_dimmer_' + msg.deviceKey);
msg.desired_hvac   = desired_hvac;
msg.desired_dimmer = desired_dimmer;
const hvac_diff   = desired_hvac   && desired_hvac   !== reported.hvac_mode;
const dimmer_diff = desired_dimmer && desired_dimmer !== reported.lighting_dimmer;
if (hvac_diff || dimmer_diff) {
  msg.needsSync = true;
  msg.syncPayload = {};
  if (hvac_diff)   msg.syncPayload.hvac_mode       = desired_hvac;
  if (dimmer_diff) msg.syncPayload.lighting_dimmer  = desired_dimmer;
  node.send([msg, null]);
} else {
  msg.needsSync = false;
  node.send([null, msg]);
}

msg.topic   = `campus/cmd/${msg.deviceKey}`;
msg.payload = JSON.stringify({ method:'applyConfig', params: msg.syncPayload });
return msg;

msg.payload = JSON.stringify({ sync_status:'OK', ts: Date.now() });
msg.topic   = 'v1/devices/me/telemetry';
return msg;

const parts = msg.topic.split('/');
const deviceId  = parts[2];
const requestId = parts[5];
let rpc;
try { rpc = JSON.parse(msg.payload); } catch(e) { return null; }
const method = rpc.method;
const params = rpc.params;
msg.topic   = `campus/cmd/${deviceId}`;
msg.payload = JSON.stringify({ method, params, requestId });
msg.deviceId   = deviceId;
msg.requestId  = requestId;
flow.set('pending_' + deviceId, { method, ts: Date.now() });
return msg;

const parts = msg.topic.split('/');
const roomId = `${parts[1]}-${parts[2]}-${parts[4]}`;
flow.set('pending_' + roomId, null);
msg.topic   = 'v1/devices/me/telemetry';
msg.payload = JSON.stringify({ cmd_ack: true, room_id: roomId, ts: Date.now() });
return msg;

const parts = msg.topic.split('/');
const building = parts[1];
const floor    = parts[2];
const room     = parts[3];
let data;
try { data = JSON.parse(msg.payload); } catch(e) { return null; }
data.building_id = building;
data.floor_id    = floor;
data.room_id     = room;
data.ts          = Date.now();
msg.payload = JSON.stringify(data);
return msg;
